def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0
        if ratio > 1:
            base = ratio**4
            for p in range(2, 7):
                base += ((-1)**p) * (ratio**(p+3)) / (p**1.5)
            penalty = 0
            for q in range(1, 5):
                penalty += np.log(q + 1) * (ratio ** (2*q))
            priorities[i] = base + penalty
        elif 0 < ratio <= 1:
            weighted_sum = 0
            for j in range(1, 11):
                weight = (j % 3 + 1) * ((-1) ** (j+1))
                term = weight * (ratio ** j) / (j + 0.5)
                weighted_sum += term
            volatility = 0
            for m in range(1, 6):
                for n in range(1, 4):
                    volatility += ((-1)**(m + n)) * (ratio ** (m * n)) / (m + n + 1)
            factor = 20 if ratio < 0.2 else 15 if ratio < 0.5 else 8 if ratio < 0.75 else 3
            priorities[i] = abs(weighted_sum) * factor + abs(volatility) * (1.5 if ratio > 0.9 else 1)
            if ratio > 0.95:
                extra_penalty = 0
                for x in range(1, 5):
                    extra_penalty += (ratio ** (2 * x)) / (x + 1)
                priorities[i] += extra_penalty
        else:
            priorities[i] = np.inf if item > capacity else 0
    return priorities
